#include <stdio.h>
int main() {
    int T, N, arr[100005], i, j, k, count, distinct;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (i = 0; i < N; i++) scanf("%d", &arr[i]);
        count = 0;
        for (i = 0; i < N; i++) {
            distinct = 0;
            int freq[100005] = {0};
            for (j = i; j < N; j++) {
                if (freq[arr[j]] == 0) distinct++;
                freq[arr[j]]++;
                if (distinct == j - i + 1) count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

