import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) arr[i] = sc.nextInt();
            int count = 0;
            for (int i = 0; i < N; i++) {
                int distinct = 0;
                int[] freq = new int[100005];
                for (int j = i; j < N; j++) {
                    if (freq[arr[j]] == 0) distinct++;
                    freq[arr[j]]++;
                    if (distinct == j - i + 1) count++;
                }
            }
            System.out.println(count);
        }
    }
}

code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t = null;
let n = null;
let arr = null;
readline.on('line', line => {
    if (i == 0) {
        t = parseInt(line);
        i++;
    } else if (i == 1) {
        n = parseInt(line);
        i++;
    } else {
        arr = line.split(' ').map(x => parseInt(x));
        let count = 0;
        for (let j = 0; j < n; j++) {
            let distinct = 0;
            let freq = new Array(100005).fill(0);
            for (let k = j; k < n; k++) {
                if (freq[arr[k]] == 0) distinct++;
                freq[arr[k]]++;
                if (distinct == k - j + 1) count++;
            }
        }
        console.log(count);
        i = 1;
        t--;
        if (t == 0) process.exit(0);
    }
});

